const raw = $input.first().json;
const lead = raw.body && typeof raw.body === 'object' ? raw.body : raw;

if (!lead.email) {
  throw new Error('Webhook payload missing email.');
}

const userPrompt = `Draft an internal sales brief from this inbound website inquiry.

Contact
- Name: ${lead.name ?? 'Not provided'}
- Email: ${lead.email}
- Company: ${lead.company || 'Not provided'}
- Phone: ${lead.phone || 'Not provided'}

Qualification
- Service needed: ${lead.service ?? 'Not specified'}
- Budget: ${lead.budget ?? 'Not specified'}
- Timeline: ${lead.timeline ?? 'Not specified'}
- Lead score: ${lead.score ?? 'Not scored'}`;

return [
  {
    json: {
      timestamp: lead.timestamp ?? new Date().toISOString(),
      name: lead.name ?? '',
      email: lead.email,
      company: lead.company ?? '',
      phone: lead.phone ?? '',
      service: lead.service ?? '',
      budget: lead.budget ?? '',
      timeline: lead.timeline ?? '',
      score: lead.score ?? '',
      status: lead.status ?? 'New',
      userPrompt,
    },
  },
];

const res = $input.first().json;

let raw =
  res.message?.content ??
  res.choices?.[0]?.message?.content ??
  res.output_text ??
  res.text;

if (!raw) {
  throw new Error(
    `No summary in model response: ${JSON.stringify(res).slice(0, 500)}`,
  );
}

function stripModelArtifacts(text) {
  let s = String(text);
  const blocks = [
    /<think>[\s\S]*?<\/redacted_thinking>/gi,
    /[\s\S]*?<\/think>/gi,
    /<thinking>[\s\S]*?<\/thinking>/gi,
  ];
  for (const pattern of blocks) {
    s = s.replace(pattern, '');
  }
  s = s.replace(/\*\*([^*]+)\*\*/g, '$1');
  return s.replace(/\n{3,}/g, '\n\n').trim();
}

const summary = stripModelArtifacts(raw);

if (summary.length < 80) {
  throw new Error('Summary too short after cleanup; check model output.');
}

return [{ json: { summary } }];

const lead = $('Normalize Lead Fields').item.json;
const scoreLabel = lead.score || 'Unscored';

// Column order must match Google Sheet row 1:
// Timestamp | Name | Email | Company | Phone | Service | Budget | Timeline | Score | Status
return [
  {
    json: {
      Timestamp: lead.timestamp,
      Name: lead.name ?? '',
      Email: lead.email,
      Company: lead.company ?? '',
      Phone: lead.phone ?? '',
      Service: lead.service ?? '',
      Budget: lead.budget ?? '',
      Timeline: lead.timeline ?? '',
      Score: scoreLabel,
      Status: lead.status ?? 'New',
    },
  },
];
